import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './Home.css';

function Home() {
  const [searchQuery, setSearchQuery] = useState('');
  const [location, setLocation] = useState('All Cities');
  const [categories, setCategories] = useState([]);
  const [stats, setStats] = useState({ products: 0, suppliers: 0, categories: 0, users: 11507060 });

  useEffect(() => {
    fetchCategories();
    fetchStats();
  }, []);

  const fetchCategories = async () => {
    try {
      const response = await axios.get('/api/categories');
      setCategories(response.data);
    } catch (error) {
      console.error('Error fetching categories:', error);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get('/api/stats');
      setStats(prev => ({ ...prev, ...response.data }));
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      window.location.href = `/products?search=${encodeURIComponent(searchQuery)}`;
    }
  };

  return (
    <div className="home">
      {/* Header Search Section */}
      <div className="home-header">
        <div className="container">
          <div className="header-search-section">
            <select 
              className="location-dropdown"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
            >
              <option>All Cities</option>
              <option>Mumbai</option>
              <option>Delhi</option>
              <option>Bangalore</option>
              <option>Chennai</option>
              <option>Kolkata</option>
            </select>
            <form onSubmit={handleSearch} className="main-search-box">
              <input
                type="text"
                placeholder="Best B2B Portal, Marketplace in India - Search Products, Suppliers, Buyers"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="main-search-input"
              />
              <button type="button" className="voice-search-btn">🎤</button>
              <button type="submit" className="main-search-btn">🔍</button>
            </form>
            <div className="user-count">
              <span>Registered Users</span>
              <strong>{stats.users.toLocaleString('en-IN')}</strong>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content Layout */}
      <div className="home-main-layout">
        <div className="container">
          <div className="home-content-grid">
            {/* Left Sidebar - Categories */}
            <aside className="categories-sidebar">
              <h3>Top Categories</h3>
              <ul className="categories-list">
                {categories.slice(0, 15).map((category) => (
                  <li key={category.id}>
                    <Link to={`/products?category=${category.id}`}>
                      <span className="category-icon-small">📦</span>
                      {category.name}
                    </Link>
                  </li>
                ))}
              </ul>
              <Link to="/products" className="view-all-categories">View all Categories →</Link>
            </aside>

            {/* Main Content Area */}
            <main className="home-main-content">
              {/* Banner Section */}
              <div className="main-banner">
                <div className="banner-content">
                  <h2>Quality for Manufacturers Since 1981</h2>
                  <p>India's Largest B2B Marketplace</p>
                </div>
                <div className="banner-products">
                  <div className="banner-product-item">🔩</div>
                  <div className="banner-product-item">⚙️</div>
                  <div className="banner-product-item">🔧</div>
                  <div className="banner-product-item">⚡</div>
                </div>
              </div>

              {/* Promotional Cards */}
              <div className="promotional-cards">
                <div className="promo-card trade-udhaar">
                  <h3>trade® Udhaar</h3>
                  <p>INSTANT, DIGITAL MSME LOAN - WHEN YOUR BUSINESS NEEDS IT</p>
                  <ul>
                    <li>✓ Disbursed in 24 H</li>
                    <li>✓ No Collateral Required</li>
                    <li>✓ Trusted by 100,000+</li>
                  </ul>
                  <p className="promo-note">The entire process is seamless.</p>
                  <button className="btn btn-white">Apply Now</button>
                </div>

                <div className="promo-card buy-requirement">
                  <h3>Looking for a Product?</h3>
                  <p>Post your buying requirement and get quotes from verified suppliers</p>
                  <Link to="/buy-requirements" className="btn btn-yellow">Post Buy Requirement</Link>
                </div>

                <div className="promo-card sell-on-tradeindia">
                  <h3>Want to grow your business 10X Faster?</h3>
                  <p>Join thousands of sellers on TradeIndia</p>
                  <Link to="/register" className="btn btn-red">Sell on TradeIndia</Link>
                </div>
              </div>

              {/* More Value Adds Section */}
              <div className="value-adds-section">
                <h3>More Value Adds</h3>
                <div className="value-adds-grid">
                  <div className="value-add-card">
                    <div className="value-add-icon">👣</div>
                    <h4>TradeIndia Tradeshows and Exhibitions</h4>
                    <button className="btn-link">Learn more</button>
                  </div>
                  <div className="value-add-card">
                    <div className="value-add-icon">🤝</div>
                    <h4>TradeIndia Buy Trade Leads</h4>
                    <button className="btn-link">Learn more</button>
                  </div>
                  <div className="value-add-card">
                    <div className="value-add-icon">📅</div>
                    <h4>TradeIndia Book Domain</h4>
                    <button className="btn-link">Learn more</button>
                  </div>
                  <div className="value-add-card">
                    <div className="value-add-icon">💳</div>
                    <h4>TradeIndia Membership Plans</h4>
                    <button className="btn-link">Learn more</button>
                  </div>
                  <div className="value-add-card">
                    <div className="value-add-icon">🏢</div>
                    <h4>Find Distributors For Your Business</h4>
                    <button className="btn-link">Learn more</button>
                  </div>
                </div>
              </div>

              {/* Trending Categories */}
              <div className="trending-categories">
                <h3>Trending Categories</h3>
                <div className="trending-grid">
                  {categories.slice(0, 8).map((category) => (
                    <Link key={category.id} to={`/products?category=${category.id}`} className="trending-item">
                      <div className="trending-icon">📦</div>
                      <span>{category.name}</span>
                    </Link>
                  ))}
                </div>
              </div>
            </main>
          </div>
        </div>
      </div>
    </div>
  );
}

